input.command:
kubectl patch statefulset mongodb-replica -n mongodb --type=strategic -p '{
  "spec": {
    "template": {
      "spec": {
        "containers": [
          {
            "name": "mongod",
            "command": ["mongod", "--config", "/etc/mongod/mongod.conf"],
            "volumeMounts": [
              {
                "name": "mongod-config",
                "mountPath": "/etc/mongod",
                "readOnly": true
              }
            ]
          }
        ],
        "volumes": [
          {
            "name": "mongod-config",
            "configMap": {
              "name": "mongod-config"
            }
          }
        ]
      }
    }
  }
}' 2>&1

for pod in mongodb-replica-0 mongodb-replica-1 mongodb-replica-2; do
  echo "=== $pod ==="
  kubectl exec -n mongodb $pod -- mongosh --quiet \
    --username admin --password admin123password \
    --authenticationDatabase admin \
    --eval "
var st = rs.status().myState;
print('Role:', st === 1 ? 'PRIMARY' : st === 2 ? 'SECONDARY' : 'state='+st);
var lv = db.adminCommand({getParameter: 1, logLevel: 1});
print('logLevel:', lv.logLevel);
var sl = db.getSiblingDB('admin').getProfilingStatus();
print('slowms:', sl.slowms);
" 2>&1
done

